// topic: coworking/<room_id>/status
const parts = msg.topic.split('/');
const room_id = parts[1];
const payload = msg.payload;

msg.payload = {
    measurement: 'occupancy',
    tags: { room_id: room_id },
    fields: {
        status: payload.status === 'busy' ? 1 : 0,
        status_str: payload.status
    },
    timestamp: new Date()
};
return msg;

// topic: coworking/<room_id>/sensors/<type>
const parts = msg.topic.split('/');
const room_id = parts[1];
const sensor_type = parts[3]; // motion or noise
const payload = msg.payload;

msg.payload = {
    measurement: 'sensors',
    tags: { room_id: room_id, sensor_type: sensor_type },
    fields: {
        value: payload.value ? 1 : 0,
        raw: payload.raw || 0
    },
    timestamp: new Date()
};
return msg;

const parts = msg.topic.split('/');
const room_id = parts[1];
const payload = msg.payload;

msg.payload = {
    measurement: 'device_health',
    tags: { room_id: room_id },
    fields: {
        online: payload.status === 'online' ? 1 : 0,
        rssi: payload.rssi || 0,
        uptime: payload.uptime || 0,
        reconnects: payload.reconnects || 0
    },
    timestamp: new Date()
};
return msg;
